<template>
  <PreHeader />
  <HeaderMenu />
  <div class="content">
    <div class="tab">
      <button
        v-for="loaitainguyen in danhsachloaitainguyen"
        :key="loaitainguyen.id"
        :class="{'tablinks': true, 'active': loaitainguyen.id === 1}"
        @click="openCity('loai-tai-nguyen-' + loaitainguyen.id)"
      >
        {{ loaitainguyen.name }}
      </button>
    </div>

    <!-- Tab content -->
    <ResourceContent v-for="i in danhsachloaitainguyen.length" :key="i" :idloaitainguyen="i" />
  </div>
  <FooterMenu />
</template>

<script>
import loaitainguyenData from "@/assets/data/loaitainguyen.json";
import PreHeader from "@/components/PreHeader.vue";
import HeaderMenu from "@/components/HeaderMenu.vue";
import FooterMenu from "@/components/FooterMenu.vue";
import ResourceContent from "@/components/ResourceContent.vue";

export default {
  name: "App",
  components: {
    PreHeader,
    HeaderMenu,
    FooterMenu,
    ResourceContent,
  },
  data() {
    return {
      danhsachloaitainguyen: loaitainguyenData,
    };
  },
  mounted(){
    this.openCity("loai-tai-nguyen-1")

  },
  methods: {
    openCity(cityName) {
      // Declare all variables
      var i, tabcontent, tablinks;

      // Get all elements with class="tabcontent" and hide them
      tabcontent = document.getElementsByClassName("tabcontent");
      for (i = 0; i < tabcontent.length; i++) {
        tabcontent[i].style.display = "none";
      }

      // Get all elements with class="tablinks" and remove the class "active"
      tablinks = document.getElementsByClassName("tablinks");
      for (i = 0; i < tablinks.length; i++) {
        tablinks[i].className = tablinks[i].className.replace(" active", "");
      }

      // Show the current tab, and add an "active" class to the button that opened the tab
      document.getElementById(cityName).style.display = "block";
    },
  },
};
</script>

<style>
@import "@/assets/css/style.css";

/* Style the tab */
.tab {
  overflow: hidden;
  border: 1px solid #ccc;
  background-color: #f1f1f1;
}

/* Style the buttons that are used to open the tab content */
.tab button {
  background-color: inherit;
  float: left;
  border: none;
  outline: none;
  cursor: pointer;
  padding: 14px 16px;
  transition: 0.3s;
}
.tab button.active {
  background-color: #ccc;
}

/* Change background color of buttons on hover */
.tab button:hover {
  background-color: #ddd;
}

/* Create an active/current tablink class */
.tab button.active {
  background-color: #ccc;
}

/* Style the tab content */
.tabcontent {
  display: none;
  padding: 6px 12px;
  border: 1px solid #ccc;
  border-top: none;
}
#app {
  font-family: Avenir, Helvetica, Arial, sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-align: center;
  color: #2c3e50;
}
</style>
