<template>
  <div :id="'loai-tai-nguyen-' + idloaitainguyen" class="tabcontent">
    <ul class="resource-list">
      <li v-for="tainguyen in danhsachtainguyen" :key="tainguyen.id">
        <a :href="tainguyen.link" target="_blank">
          <img :src="require('@/assets/images/' + imagesFor(tainguyen.extension))" alt="">
          <span>{{ tainguyen.name }}</span>
        </a>
      </li>
    </ul>
  </div>
</template>
<script>
import tainguyenData from "@/assets/data/tainguyen.json";

export default {
  name: "ResourceContent",
  props: {
    idloaitainguyen: Number,
  },
  data() {
    let tainguyenToShow = tainguyenData.reduce((filtered, tainguyen) => {
      if (tainguyen.idloaitainguyen == this.idloaitainguyen) {
        let filteredtainguyen = Object.assign({}, tainguyen);
        filtered.push(filteredtainguyen);
      }
      return filtered;
    }, []);
    return {
      danhsachtainguyen: tainguyenToShow,
    };
  },
  methods: {
    imagesFor(ext) {
      switch (ext) {
        case "folder":
          return "thu-muc.png";         
        case "exe":
          return "phan-mem.png";         
        case "pptx":
          return "bai-giang.png";         
        case "docx":
          return "ke-hoach.png";
        default:
          return "danh-gia.png";
      }
    }
  }
};
</script>

